  1→import React, {useCallback, useEffect, useMemo, useState} from 'react';
  2→import {ActivityIndicator, Image, StyleSheet, View} from 'react-native';
  3→import {useQuery} from '@tanstack/react-query';
  4→import {NativeStackScreenProps} from '@react-navigation/native-stack';
  5→import {SafeAreaView} from 'react-native-safe-area-context';
  6→import LinearGradient from 'react-native-linear-gradient';
  7→import {useAuth} from '../../features/auth/AuthProvider';
  8→import {useTheme} from '../../theme/ThemeProvider';
  9→import {mobileApi} from '../../lib/api/mobileApi';
 10→import {ProfileHeroSection} from './ProfileHeroSection';
 11→import {ProfileTabBar, type ProfileTab} from './ProfileTabBar';
 12→import {ProfileWritingsTab} from './ProfileWritingsTab';
 13→import {ProfileStoriesTab} from './ProfileStoriesTab';
 14→import {PrimaryButton} from '../../components/PrimaryButton';
 15→import {
 16→  parseProfileBackground,
 17→  cssAngleToGradientPoints,
 18→} from '../../lib/utils/profileBackground';
 19→import type {RootStackParamList} from '../../navigation/types';
 20→
 21→type Props = NativeStackScreenProps<RootStackParamList, 'VisitProfile'>;
 22→
 23→export function VisitProfileScreen({route, navigation}: Props) {
 24→  const {userId} = route.params;
 25→  const {user} = useAuth();
 26→  const {colors} = useTheme();
 27→  const [activeTab, setActiveTab] = useState<ProfileTab>('writings');
 28→
 29→  // Self-redirect guard
 30→  useEffect(() => {
 31→    if (userId === user?.id) {
 32→      navigation.replace('Main' as any, {screen: 'Profile'});
 33→    }
 34→  }, [userId, user?.id, navigation]);
 35→
 36→  const userDataQuery = useQuery({
 37→    queryKey: ['profile', userId],
 38→    enabled: Boolean(userId) && userId !== user?.id,
 39→    queryFn: () => mobileApi.getUserData(userId),
 40→  });
 41→
 42→  const streakQuery = useQuery({
 43→    queryKey: ['streak', userId],
 44→    enabled: Boolean(userId) && userId !== user?.id,
 45→    queryFn: () => mobileApi.getStreak(userId),
 46→  });
 47→
 48→  const profile = userDataQuery.data?.userData?.[0] ?? null;
 49→  const streak = streakQuery.data?.currentStreak;
 50→
 51→  // Set header title dynamically
 52→  useEffect(() => {
 53→    if (profile?.name) {
 54→      navigation.setOptions({title: profile.name});
 55→    }
 56→  }, [profile?.name, navigation]);
 57→
 58→  const parsedBg = useMemo(
 59→    () => parseProfileBackground(profile?.background),
 60→    [profile?.background],
 61→  );
 62→
 63→  const onFollowersPress = useCallback(() => {
 64→    navigation.navigate('FollowList', {userId, tab: 'followers'});
 65→  }, [navigation, userId]);
 66→
 67→  const onFollowingPress = useCallback(() => {
 68→    navigation.navigate('FollowList', {userId, tab: 'following'});
 69→  }, [navigation, userId]);
 70→
 71→  if (userId === user?.id) {
 72→    return null;
 73→  }
 74→
 75→  if (userDataQuery.isLoading) {
 76→    return (
 77→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
 78→        <View style={styles.loadingContainer}>
 79→          <ActivityIndicator color={colors.loaderColor} size="large" />
 80→        </View>
 81→      </SafeAreaView>
 82→    );
 83→  }
 84→
 85→  const followButton = (
 86→    <PrimaryButton label="Follow" onPress={() => {}} />
 87→  );
 88→
 89→  const headerComponent = (
 90→    <View>
 91→      <ProfileHeroSection
 92→        profile={profile}
 93→        streak={streak}
 94→        onFollowersPress={onFollowersPress}
 95→        onFollowingPress={onFollowingPress}
 96→        actionButton={followButton}
 97→      />
 98→      <ProfileTabBar activeTab={activeTab} onTabChange={setActiveTab} />
 99→      <View style={styles.tabSpacer} />
100→    </View>
101→  );
102→
103→  const backdropElement = useMemo(() => {
104→    if (parsedBg.type === 'gradient') {
105→      const {start, end} = cssAngleToGradientPoints(parsedBg.angle);
106→      return (
107→        <LinearGradient
108→          colors={parsedBg.colors}
109→          locations={parsedBg.locations}
110→          start={start}
111→          end={end}
112→          style={[StyleSheet.absoluteFill, styles.backdrop]}
113→        />
114→      );
115→    }
116→    if (parsedBg.type === 'image') {
117→      const dominantArr = profile?.dominant_colors
118→        ? profile.dominant_colors.split(',').map(c => c.trim())
119→        : null;
120→      const secondaryArr = profile?.secondary_colors
121→        ? profile.secondary_colors.split(',').map(c => c.trim())
122→        : null;
123→      const hasGradientOverlay =
124→        dominantArr && dominantArr.length > 0 && secondaryArr && secondaryArr.length > 0;
125→      return (
126→        <View style={[StyleSheet.absoluteFill, styles.backdrop]}>
127→          {hasGradientOverlay && (
128→            <LinearGradient
129→              colors={[...dominantArr, ...secondaryArr]}
130→              style={StyleSheet.absoluteFill}
131→            />
132→          )}
133→          <Image
134→            source={{uri: parsedBg.uri}}
135→            blurRadius={40}
136→            style={[StyleSheet.absoluteFill, {opacity: 0.3}]}
137→            resizeMode="cover"
138→          />
139→        </View>
140→      );
141→    }
142→    return null;
143→  }, [parsedBg, profile?.dominant_colors, profile?.secondary_colors]);
144→
145→  return (
146→    <SafeAreaView
147→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
148→      edges={['top']}>
149→      {backdropElement}
150→
151→      {activeTab === 'writings' ? (
152→        <ProfileWritingsTab
153→          userId={userId}
154→          headerComponent={headerComponent}
155→        />
156→      ) : (
157→        <ProfileStoriesTab
158→          userId={userId}
159→          headerComponent={headerComponent}
160→        />
161→      )}
162→    </SafeAreaView>
163→  );
164→}
165→
166→const styles = StyleSheet.create({
167→  safe: {
168→    flex: 1,
169→  },
170→  loadingContainer: {
171→    flex: 1,
172→    alignItems: 'center',
173→    justifyContent: 'center',
174→  },
175→  tabSpacer: {
176→    height: 12,
177→  },
178→  backdrop: {
179→    opacity: 0.15,
180→    transform: [{scale: 1.4}],
181→  },
182→});
183→

  1→import React, {useMemo} from 'react';
  2→import {ImageBackground, Pressable, Share, StyleSheet, Text, View} from 'react-native';
  3→import LinearGradient from 'react-native-linear-gradient';
  4→import {Avatar} from '../../components/Avatar';
  5→import {PrimaryButton} from '../../components/PrimaryButton';
  6→import {FireIcon, SettingsIcon, ShareIcon} from '../../components/icons';
  7→import {useTheme} from '../../theme/ThemeProvider';
  8→import {fonts, typeScale} from '../../theme/typography';
  9→import {spacing, radii} from '../../theme/spacing';
 10→import {
 11→  parseProfileBackground,
 12→  cssAngleToGradientPoints,
 13→  type ParsedProfileBg,
 14→} from '../../lib/utils/profileBackground';
 15→
 16→interface ProfileHeroProps {
 17→  profile: {
 18→    id: string;
 19→    name?: string;
 20→    username?: string;
 21→    bio?: string;
 22→    image_url?: string;
 23→    badge_type?: string;
 24→    profile_layout?: any;
 25→    followers_count?: number;
 26→    following_count?: number;
 27→    posts_count?: number;
 28→    background?: Record<string, string> | null;
 29→    profile_font_color?: string | null;
 30→    dominant_colors?: string | null;
 31→    secondary_colors?: string | null;
 32→  } | null;
 33→  streak?: number;
 34→  email?: string;
 35→  onEditProfile?: () => void;
 36→  onSettingsPress?: () => void;
 37→  onFollowersPress: () => void;
 38→  onFollowingPress: () => void;
 39→  actionButton?: React.ReactNode;
 40→}
 41→
 42→export function ProfileHeroSection({
 43→  profile,
 44→  streak,
 45→  email,
 46→  onEditProfile,
 47→  onSettingsPress,
 48→  onFollowersPress,
 49→  onFollowingPress,
 50→  actionButton,
 51→}: ProfileHeroProps) {
 52→  const {colors} = useTheme();
 53→  const bgColor = profile?.profile_layout?.backgroundColor ?? colors.accentAmber;
 54→
 55→  const parsedBg = useMemo(
 56→    () => parseProfileBackground(profile?.background),
 57→    [profile?.background],
 58→  );
 59→
 60→  const fontColor = profile?.profile_font_color || null;
 61→  const nameColor = fontColor || colors.textHeading;
 62→  const mutedColor = fontColor ? `${fontColor}99` : colors.textMuted;
